sys_script_include.script:
var RequestUtils = Class.create();


RequestUtils.prototype = {
    initialize: function() {},

    shouldApplyFilter: function(current) {

        // Never filter background system processes (Jobs, Integrations)
        if (!gs.getSession().isInteractive()) return false;

        const transaction = GlideTransaction.get();

        if (!transaction) return false;

        const requestURL = transaction.getRequest().getRequestURL().toString();

        // IDENTIFY THE SCENARIO
        // Scenario A: Standard List View (Usually contains 'incident_list.do')
        const isList = requestURL.indexOf('_list.do') > -1;

        // Scenario B: Global Search (User typing in the top-right search bar)
        const isGlobalSearch = requestURL.indexOf('sys_search.do') > -1;

        // Scenario C: Reference Lookup (The magnifying glass)
        const isLookup = requestURL.indexOf('xmlhttp.do') > -1 &&
            transaction.getRequestParameter('sysparm_processor') == 'XMLHttpLookup';

        // Apply filtering ONLY if it's a primary list view or global search
        // We exclude scenarios like 'fetching a single row' or 'distinct counts'
        return isList || isGlobalSearch || isLookup;
    },

    getOperation: function(current, previous) {
        // 1. Check for Query
        // In a Query trigger, current exists but has no Sys ID and isn't a "New Record"
        if (!current.getUniqueValue() && !current.isNewRecord()) {
            return 'query';
        }

        // 2. Check for Insert
        if (current.isNewRecord()) {
            return 'insert';
        }

        // 3. Check for Delete
        // isDeleting() is the most reliable flag when operation() is null
        if (current.isDeleting()) {
            return 'delete';
        }

        // 4. Check for Update
        // If it has a Sys ID, isn't new, and isn't deleting, it must be an update
        if (current.getUniqueValue() && !current.isDeleting()) {
            return 'update';
        }

        return null;
    },

    type: 'RequestUtils'
};
